        assert employee_id, "Employee ID is required in test data/config_data"

        endpoint = _ENDPOINT.replace("{id}", employee_id)
        resp = api_client.get(endpoint)

        assert resp.status_code == entry["statusCode"], (
            f"Expected {entry['statusCode']} but got {resp.status_code} for id={employee_id} ({entry.get('scenario')})"
        )

